1	const PROCESSING_FEE = 5;
2	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
3	  sword: 100,
4	  amulet: 60,
5	  staff: 80,
6	  potion: 40,
7	  rune: 25,
8	  moonstone: 25,
9	};
10	
11	type Item = { type: string };
12	type Step = { type: string; items: Item[] };
13	
14	export function runScenario(steps: Step[]): unknown[] {
15	  return steps.map((step) => ({
16	    premium:
17	      PROCESSING_FEE +
18	      step.items.reduce(
19	        (sum, item) => sum + BASE_PREMIUM_BY_TYPE[item.type],
20	        0,
21	      ),
22	  }));
23	}
